const resolveInvoicePaymentLifecycle = (row) => {
  if (!row || isDraftInvoiceRow(row) || isReceivableApprovalInvoiceRow(row)) {
    return { key: 'draft', label: '-', color: '#6b7280' };
  }

  const providerPaymentStatus = normalizeDanaQrisStatus(
    row?.provider_payment?.status
    || row?.providerPayment?.status
    || '',
  );
  if (providerPaymentStatus === 'pending') {
    const providerPaymentLabel = String(
      row?.provider_payment?.methodLabel
      || row?.provider_payment?.payment_method_label
      || row?.providerPayment?.methodLabel
      || row?.providerPayment?.payment_method_label
      || 'Pembayaran Online',
    ).trim();
    return {
      key: 'provider_pending',
      label: `Menunggu ${providerPaymentLabel}`,
      color: '#1849a9',
    };
  }

  const total = roundMoney(Number(
    row?.invoice?.total
    || row?.total
    || row?.grand_total
    || 0
  ));
  const paidTotal = roundMoney(Number(row?.invoice?.paid_total || row?.paid_total || 0));
  const dueTotal = roundMoney(Math.max(0, Number(row?.invoice?.due_total || Math.max(total - paidTotal, 0))));

  if (total > 0 && dueTotal <= 0) {
    return { key: 'paid', label: 'Lunas', color: '#067647' };
  }

  return { key: 'unpaid', label: 'Belum Lunas', color: '#8a6b00' };
};
const resolveInvoiceProductionLifecycle = (row) => {
  if (!row || isDraftInvoiceRow(row)) {
    return { key: 'draft', label: 'Belum Masuk Produksi', color: '#6b7280' };
  }

  const counts = getProductionCountsForInvoice(row);
  if (!counts) {
    return { key: 'not_required', label: 'Tidak Perlu Produksi', color: '#475467' };
  }

  const unfinished = Number(counts.waiting_design || 0) + Number(counts.waiting_production || 0) + Number(counts.in_batch || 0);
  const finished = Number(counts.printed || 0);
  const total = unfinished + finished;
  const progressPercent = total > 0 ? Math.round((finished / total) * 100) : 0;
  if (unfinished > 0) {
    return {
      key: 'started',
      label: `Progress ${progressPercent}% (${finished}/${total} item selesai)`,
      color: finished > 0 ? '#1849a9' : '#b54708',
    };
  }

  if (finished > 0) {
    return { key: 'finished', label: `Selesai Produksi (${finished}/${total || finished} item)`, color: '#067647' };
  }

  return { key: 'not_required', label: 'Tidak Perlu Produksi', color: '#475467' };
};
const getProductionCountsForInvoice = (row) => {
  const resolveProofingFallbackCounts = () => {
    const proofingSummary = row?.proofing && typeof row.proofing === 'object' ? row.proofing : null;
    if (proofingSummary?.enabled === true) {
      const total = Math.max(Number(proofingSummary?.item_count || 0) || 0, 0);
      const draft = Math.max(Number(proofingSummary?.draft || 0) || 0, 0);
      const sent = Math.max(Number(proofingSummary?.sent || 0) || 0, 0);
      const approved = Math.max(Number(proofingSummary?.approved || 0) || 0, 0);
      const revision = Math.max(Number(proofingSummary?.revision || 0) || 0, 0);
      const fallbackCount = Math.max(total, approved);
      if (fallbackCount > 0 && draft <= 0 && sent <= 0 && revision <= 0 && approved > 0) {
        return {
          waiting_design: 0,
          waiting_production: fallbackCount,
          in_batch: 0,
          printed: 0,
        };
      }
    }
    return null;
  };

  const summarizedProduction = row?.production && typeof row.production === 'object' ? row.production : null;
  if (summarizedProduction) {
    const counts = {
      waiting_design: Number(summarizedProduction?.waiting_design || 0) || 0,
      waiting_production: Number(summarizedProduction?.waiting_production || 0) || 0,
      in_batch: Number(summarizedProduction?.in_batch || 0) || 0,
      printed: Number(summarizedProduction?.printed || 0) || 0,
    };
    const totalTracked = Object.values(counts).reduce((sum, val) => sum + Number(val || 0), 0);
    if (totalTracked > 0) {
      return counts;
    }
  }

  const items = Array.isArray(row?.items) ? row.items : [];
  if (items.length === 0) {
    return resolveProofingFallbackCounts();
  }
  const counts = {
    waiting_design: 0,
    waiting_production: 0,
    in_batch: 0,
    printed: 0,
  };
  items.forEach((item) => {
    const status = resolveProductionStatusKey(item?.production_status);
    if (Object.prototype.hasOwnProperty.call(counts, status)) {
      counts[status] += 1;
    }
  });
  const totalTracked = Object.values(counts).reduce((sum, val) => sum + Number(val || 0), 0);
  if (totalTracked <= 0) {
    return resolveProofingFallbackCounts();
  }
  return counts;
};
const getInvoiceRowItemCount = (row) => {
  const explicitCount = Number(row?.item_count ?? row?.production?.item_count ?? 0) || 0;
  if (explicitCount > 0) {
    return explicitCount;
  }
  return Array.isArray(row?.items) ? row.items.length : 0;
};
const summarizeProductionStatusForInvoice = (row) => {
  const counts = getProductionCountsForInvoice(row);
  if (!counts) {
    return '-';
  }
  const total = Number(counts.waiting_design || 0)
    + Number(counts.waiting_production || 0)
    + Number(counts.in_batch || 0)
    + Number(counts.printed || 0);
  const printed = Number(counts.printed || 0);
  const percent = total > 0 ? Math.round((printed / total) * 100) : 0;
  return `Progress ${percent}% (${printed}/${total} selesai) | Design ${counts.waiting_design} | Produksi ${counts.waiting_production} | Batch ${counts.in_batch} | Selesai ${counts.printed}`;
};
const getCurrentProductionStageForInvoice = (row) => {
  const counts = getProductionCountsForInvoice(row);
  if (!counts) {
    return { key: '', label: '-', count: 0 };
  }
  if (counts.waiting_design > 0) {
    return {
      key: 'waiting_design',
      label: formatProductionStatusLabel('waiting_design'),
      count: counts.waiting_design,
    };
  }
  if (counts.waiting_production > 0) {
    return {
      key: 'waiting_production',
      label: formatProductionStatusLabel('waiting_production'),
      count: counts.waiting_production,
    };
  }
  if (counts.in_batch > 0) {
    return {
      key: 'in_batch',
      label: formatProductionStatusLabel('in_batch'),
      count: counts.in_batch,
    };
  }
  if (counts.printed > 0) {
    return {
      key: 'printed',
      label: formatProductionStatusLabel('printed'),
      count: counts.printed,
    };
  }
  return { key: '', label: '-', count: 0 };
};
const buildCustomerTrackingSummary = (row) => {
  const proofingSummary = row?.proofing && typeof row.proofing === 'object' ? row.proofing : null;
  const baseProofingSummary = buildOrderProofingSummary(proofingSummary);
  const counts = getProductionCountsForInvoice(row);
  const stage = getCurrentProductionStageForInvoice(row);

  if (!proofingSummary || proofingSummary.enabled !== true) {
    return {
      sectionLabel: 'Proofing',
      label: baseProofingSummary.label,
      color: baseProofingSummary.color,
      note: baseProofingSummary.note,
      mode: 'proofing',
    };
  }

  const total = Math.max(Number(proofingSummary?.item_count || 0) || 0, 0);
  const draft = Math.max(Number(proofingSummary?.draft || 0) || 0, 0);
  const sent = Math.max(Number(proofingSummary?.sent || 0) || 0, 0);
  const approved = Math.max(Number(proofingSummary?.approved || 0) || 0, 0);
  const revision = Math.max(Number(proofingSummary?.revision || 0) || 0, 0);
  const allApproved = total > 0 && approved >= total && draft <= 0 && sent <= 0 && revision <= 0;
  const productionStarted = Boolean(
    counts
    && (Number(counts.waiting_design || 0) > 0
      || Number(counts.waiting_production || 0) > 0
      || Number(counts.in_batch || 0) > 0
      || Number(counts.printed || 0) > 0)
  );

  if (!allApproved && !productionStarted) {
    return {
      sectionLabel: 'Proofing',
      label: baseProofingSummary.label,
      color: baseProofingSummary.color,
      note: baseProofingSummary.note,
      mode: 'proofing',
    };
  }

  const stageKey = stage.key || (allApproved ? 'waiting_production' : '');
  const stageColor = stageKey ? getProductionStatusTextColor(stageKey) : '#1849a9';
  const stageCount = Number(stage.count || 0) || 0;
  const stageLabel = stage.label && stage.label !== '-'
    ? `${stage.label}${stageCount > 0 ? ` (${stageCount} item)` : ''}`
    : (allApproved ? 'Menunggu Produksi' : 'Tracking Produksi');
  const noteParts = [];
  if (String(proofingSummary?.latest_approved_at || '').trim()) {
    noteParts.push(`Proofing selesai ${formatProofingEventDateTime(proofingSummary.latest_approved_at)}`);
  }
  if (counts) {
    noteParts.push(summarizeProductionStatusForInvoice(row));
  } else if (allApproved) {
    noteParts.push('Customer sudah approve proofing. Tim produksi bisa mulai menindaklanjuti order ini.');
  }

  return {
    sectionLabel: 'Status Produksi',
    label: stageLabel,
    color: stageColor,
    note: noteParts.filter(Boolean).join(' | '),
    mode: 'production',
  };
};
const buildInvoiceItemTrackingState = (item, proofingRequired, proofingRow, proofingReleaseState) => {
  if (!proofingRequired) {
    return {
      mode: 'production',
      sectionLabel: 'Status Produksi',
      label: formatProductionStatusLabel(item?.production_status),
      color: getProductionStatusTextColor(item?.production_status),
      note: '',
    };
  }

  const productionStatusKey = resolveProductionStatusKey(item?.production_status);
  if (productionStatusKey && productionStatusKey !== 'not_required') {
    return {
      mode: 'production',
      sectionLabel: 'Status Produksi',
      label: formatProductionStatusLabel(productionStatusKey),
      color: getProductionStatusTextColor(productionStatusKey),
      note: proofingReleaseState?.releasedToProduction
        ? 'Proofing customer sudah selesai dan item ini sedang diproses produksi.'
        : '',
    };
  }

  if (proofingReleaseState?.proofingApproved) {
    const waitingLabel = proofingReleaseState?.paymentReady
      ? 'Menunggu Produksi'
      : 'Menunggu Gate Produksi';
    const waitingNote = proofingReleaseState?.paymentReady
      ? 'Customer sudah approve proofing. Item menunggu tim produksi mulai bekerja.'
      : 'Customer sudah approve proofing, tetapi item masih menunggu syarat pembayaran/gate produksi.';
    return {
      mode: 'production',
      sectionLabel: 'Status Produksi',
      label: waitingLabel,
      color: getProductionStatusTextColor('waiting_production'),
      note: waitingNote,
    };
  }

  return {
    mode: 'proofing',
    sectionLabel: 'Proofing',
    label: proofingRow ? proofingStatusToLabel(proofingRow?.status) : 'Belum dibuat',
    color: proofingRow ? getProofingStatusTextColor(proofingRow?.status) : '#92400e',
    note: '',
  };
};
const resolveProductionStatusKey = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  if (!raw) return '';
  if (['waiting_design', 'design', 'menunggu_design', 'menunggu design'].includes(raw)) {
    return 'waiting_design';
  }
  if (['waiting_production', 'menunggu_produksi', 'menunggu produksi', 'production'].includes(raw)) {
    return 'waiting_production';
  }
  if (['in_batch', 'batch', 'proses', 'proses_produksi', 'proses produksi'].includes(raw)) {
    return 'in_batch';
  }
  if (
    [
      'printed',
      'finalize',
      'finalized',
      'finished',
      'done',
      'completed',
      'ready_pickup',
      'ready_for_pickup',
      'siap_ambil',
      'siap ambil',
      'selesai',
    ].includes(raw)
  ) {
    return 'printed';
  }
  return raw;
};
const formatProductionStatusLabel = (value) => {
  const key = resolveProductionStatusKey(value);
  if (key === 'waiting_design') return 'Menunggu Design';
  if (key === 'waiting_production') return 'Menunggu Produksi';
  if (key === 'in_batch') return 'In Batch';
  if (key === 'printed') return 'Printed / Selesai';
  if (key === 'not_required') return 'Tidak Perlu Produksi';
  return humanizeStatusLabel(key);
};
const getProductionStatusTextColor = (value) => {
  const key = resolveProductionStatusKey(value);
  if (key === 'waiting_design') return '#b42318';
  if (key === 'waiting_production') return '#b54708';
  if (key === 'in_batch') return '#1849a9';
  if (key === 'printed') return '#067647';
  if (key === 'not_required') return '#475467';
  return '#2f2f2f';
};
const buildProductionNotifyText = (row, previousStatus = '') => {
  const itemId = Number(row?.id || 0);
  const invoiceNo = toLabel(row?.order?.invoice?.invoice_no, `Item #${itemId || '-'}`);
  const productName = toLabel(row?.product?.name, row?.product_name, `Produk #${Number(row?.pos_product_id || 0)}`);
  const currentStatus = formatProductionStatusLabel(row?.production_status);
  const previousLabel = formatProductionStatusLabel(previousStatus);
  if (previousStatus && String(previousStatus).trim().toLowerCase() !== String(row?.production_status || '').trim().toLowerCase()) {
    return `${invoiceNo} | ${productName}: ${previousLabel} -> ${currentStatus}`;
  }
  return `${invoiceNo} | ${productName}: update ${currentStatus}`;
};
