const isDraftCandidate = (row) => {
  if (isReceivableApprovalInvoiceRow(row)) {
    return false;
  }

  const statusCandidates = [
    row?.status,
    row?.order_status,
    row?.order?.status,
    row?.order?.order_status,
    row?.invoice?.status,
    row?.invoice?.order_status,
  ];
  if (statusCandidates.some((status) => resolveInvoiceStatusKey(status) === 'draft')) {
    return true;
  }

  const notes = [
    row?.notes,
    row?.note,
    row?.order?.notes,
    row?.order?.note,
    row?.invoice?.notes,
    row?.invoice?.note,
  ].filter(Boolean).join('\n').toLowerCase();
  if (notes.includes('sales_draft')) {
    return true;
  }
  if (notes.includes('mode: simpan draft') && !notes.includes('mode: proses orderan')) {
    return true;
  }

  const isDraftCompatibleStatus = (status) => {
    const key = resolveInvoiceStatusKey(status);
    return key === '' || key === 'pending' || key === 'draft';
  };
  const snapshotCandidates = [
    row?.draft_form,
    row?.draft_snapshot,
    row?.spec_snapshot,
    row?.order?.draft_form,
    row?.order?.draft_snapshot,
    row?.order?.spec_snapshot,
  ];
  const sourceRows = []
    .concat(Array.isArray(row?.items) ? row.items : [])
    .concat(Array.isArray(row?.order_items) ? row.order_items : [])
    .concat(Array.isArray(row?.order?.items) ? row.order.items : []);
  sourceRows.forEach((item) => {
    snapshotCandidates.push(item?.draft_form, item?.draft_snapshot, item?.spec_snapshot);
  });
  const hasLegacyDraftSnapshot = snapshotCandidates.some((value) => {
    const snapshot = parseJsonObject(value) || {};
    return Boolean(
      snapshot?.draft_form
      || snapshot?.draft_restore
      || snapshot?.is_draft
    );
  });

  return !notes.includes('mode: proses orderan')
    && isDraftCompatibleStatus(row?.status || row?.order_status || row?.order?.status)
    && isDraftCompatibleStatus(row?.invoice?.status)
    && hasLegacyDraftSnapshot;
};
const hasSnapshotObjectShape = (value) => Boolean(
  value
  && typeof value === 'object'
  && !Array.isArray(value)
  && Object.keys(value).length > 0
);
const resolveDraftSnapshotState = (row) => {
  if (String(row?.__source || '').toLowerCase() === 'queue') {
    return {
      key: 'queue',
      label: 'Antrian Offline',
      color: '#475467',
      backgroundColor: '#f2f4f7',
    };
  }

  const summarizedState = row?.draft_snapshot_state;
  if (summarizedState && typeof summarizedState === 'object' && !Array.isArray(summarizedState)) {
    return summarizedState;
  }

  const items = Array.isArray(row?.items) ? row.items : [];
  if (items.length === 0) {
    return {
      key: 'unknown',
      label: 'Snapshot Belum Dicek',
      color: '#b54708',
      backgroundColor: '#fff7ed',
    };
  }

  const snapshotFlags = items.map((item) => {
    const snapshot = parseJsonObject(item?.spec_snapshot) || {};
    const cartRestore = parseJsonObject(snapshot?.cart_restore) || snapshot?.cart_restore || {};
    const draftRestore = parseJsonObject(snapshot?.draft_restore) || snapshot?.draft_restore || {};
    const originalFlow = parseJsonObject(snapshot?.original_flow) || snapshot?.original_flow || {};
    const draftForm = parseJsonObject(snapshot?.draft_form) || snapshot?.draft_form || {};
    return {
      pricingLocked: Boolean(cartRestore?.pricing_locked || draftRestore?.pricing_locked),
      hasCartRestore: hasSnapshotObjectShape(cartRestore),
      hasDraftRestore: hasSnapshotObjectShape(draftRestore),
      hasOriginalFlow: hasSnapshotObjectShape(originalFlow),
      hasDraftForm: hasSnapshotObjectShape(draftForm),
    };
  });

  const allLocked = snapshotFlags.every((item) => item.pricingLocked);
  if (allLocked) {
    return {
      key: 'locked',
      label: 'Snapshot Terkunci',
      color: '#067647',
      backgroundColor: '#ecfdf3',
    };
  }

  const hasLegacyDraftForm = snapshotFlags.some((item) => (
    item.hasDraftForm
    && !item.hasCartRestore
    && !item.hasDraftRestore
    && !item.hasOriginalFlow
  ));
  if (hasLegacyDraftForm) {
    return {
      key: 'legacy',
      label: 'Draft Lama',
      color: '#b54708',
      backgroundColor: '#fff7ed',
    };
  }

  const hasModernSnapshot = snapshotFlags.some((item) => (
    item.hasCartRestore || item.hasDraftRestore || item.hasOriginalFlow
  ));
  if (hasModernSnapshot) {
    return null;
  }

  return {
    key: 'minimal',
    label: 'Perlu Cek Ulang',
    color: '#b42318',
    backgroundColor: '#fef3f2',
  };
};
