  const flushQueuedOrders = async (forceRun = false) => {
    const queue = loadOrderQueue();
    if ((!backendReady && !forceRun) || queue.length === 0) {
      return { successCount: 0, remaining: queue.length };
    }

    const stillQueued = [];
    let successCount = 0;
    let blockedCount = 0;
    let blockedMessage = '';

    for (const queued of queue) {
      try {
        const created = await createPosOrder(queued.payload);
        syncInvoiceSuccessCacheFromRows([created]);
        const createdId = Number(created?.id || 0) || null;
        if (isDraftPayload(queued?.payload) && createdId) {
          try {
            await updatePosOrderStatus(createdId, 'draft');
          } catch (_error) {
            // no-op
          }
        }
        successCount += 1;
      } catch (error) {
        stillQueued.push(queued);
        if (isCustomerProcessLockError(error)) {
          blockedCount += 1;
          blockedMessage = buildCustomerProcessLockNotice(error, String(queued?.payload?.customer_name || '').trim());
        }
      }
    }

    setOrderQueue(stillQueued);
    setQueueCount(stillQueued.length);

    const syncSummaries = [];
    if (successCount > 0) {
      syncSummaries.push(`Sinkronisasi offline berhasil: ${successCount} order.`);
      setAuditLogs(
        appendOrderAuditLog({
          result: 'flush_queue_success',
          synced_count: successCount,
          queue_count: stillQueued.length,
        }),
      );
    }
    if (blockedCount > 0) {
      syncSummaries.push(`Sinkronisasi tertahan: ${blockedCount} order masih terkunci draft/approval aktif.`);
      setAuditLogs(
        appendOrderAuditLog({
          result: 'flush_queue_blocked',
          blocked_count: blockedCount,
          queue_count: stillQueued.length,
          error: blockedMessage || 'Order offline tertahan karena customer masih punya draft/approval aktif.',
        }),
      );
    }
    if (syncSummaries.length > 0) {
      setLastSyncInfo(syncSummaries.join(' | '));
    }
    return { successCount, remaining: stillQueued.length };
  };

  useEffect(() => {
    if (backendReady) {
      flushQueuedOrders();
    }
  }, [backendReady]);

